//!
//! Creates two sessions programmatically, saves them as JSONL, runs the binary
//! on them, and asserts the output contains expected diff markers.

use std::process::Command;

use runtime::{ContentBlock, ConversationMessage, Session, SessionCompaction, TokenUsage};

fn build_old_session() -> Session {
    let mut session = Session::new();

    // User message
    session
        .push_message(ConversationMessage::user_text("Hello, what can you do?"))
        .unwrap();

    // Assistant reply with usage
    session
        .push_message(ConversationMessage::assistant_with_usage(
            vec![ContentBlock::Text {
                text: "I can help with many tasks!".to_string(),
            }],
            Some(TokenUsage {
                input_tokens: 100,
                output_tokens: 20,
                cache_creation_input_tokens: 0,
                cache_read_input_tokens: 0,
            }),
        ))
        .unwrap();

    // User follow-up
    session
        .push_message(ConversationMessage::user_text("Search for TODOs"))
        .unwrap();

    // Assistant with tool use
    session
        .push_message(ConversationMessage::assistant_with_usage(
            vec![
                ContentBlock::Text {
                    text: "Let me search.".to_string(),
                },
                ContentBlock::ToolUse {
                    id: "tu_1".to_string(),
                    name: "grep_search".to_string(),
                    input: r#"{"pattern":"TODO"}"#.to_string(),
                },
            ],
            Some(TokenUsage {
                input_tokens: 200,
                output_tokens: 40,
                cache_creation_input_tokens: 10,
                cache_read_input_tokens: 5,
            }),
        ))
        .unwrap();

    // Tool result
    session
        .push_message(ConversationMessage::tool_result(
            "tu_1",
            "grep_search",
            "src/main.rs:5: // TODO: fix this",
            false,
        ))
        .unwrap();

    session
}

fn build_new_session() -> Session {
    let mut session = Session::new();

    // Same first user message (unchanged)
    session
        .push_message(ConversationMessage::user_text("Hello, what can you do?"))
        .unwrap();

    // Modified assistant reply — different text and higher token usage
    session
        .push_message(ConversationMessage::assistant_with_usage(
            vec![ContentBlock::Text {
                text: "I can help with coding, debugging, and more!".to_string(),
            }],
            Some(TokenUsage {
                input_tokens: 150,
                output_tokens: 30,
                cache_creation_input_tokens: 0,
                cache_read_input_tokens: 50,
            }),
        ))
        .unwrap();

    // Same follow-up
    session
        .push_message(ConversationMessage::user_text("Search for TODOs"))
        .unwrap();

    // Same tool-use assistant (unchanged)
    session
        .push_message(ConversationMessage::assistant_with_usage(
            vec![
                ContentBlock::Text {
                    text: "Let me search.".to_string(),
                },
                ContentBlock::ToolUse {
                    id: "tu_1".to_string(),
                    name: "grep_search".to_string(),
                    input: r#"{"pattern":"TODO"}"#.to_string(),
                },
            ],
            Some(TokenUsage {
                input_tokens: 200,
                output_tokens: 40,
                cache_creation_input_tokens: 10,
                cache_read_input_tokens: 5,
            }),
        ))
        .unwrap();

    // Same tool result
    session
        .push_message(ConversationMessage::tool_result(
            "tu_1",
            "grep_search",
            "src/main.rs:5: // TODO: fix this",
            false,
        ))
        .unwrap();

    // NEW: additional assistant message (added in new session)
    session
        .push_message(ConversationMessage::assistant_with_usage(
            vec![ContentBlock::Text {
                text: "Found one TODO. I will fix it now.".to_string(),
            }],
            Some(TokenUsage {
                input_tokens: 400,
                output_tokens: 25,
                cache_creation_input_tokens: 0,
                cache_read_input_tokens: 100,
            }),
        ))
        .unwrap();

    // Record a compaction event (new session has one, old does not)
    session.record_compaction("Summarized early conversation about capabilities.", 2);

    session
}

#[test]
fn session_diff_reports_changes() {
    let dir = tempfile::tempdir().expect("create temp dir");
    let old_path = dir.path().join("old.jsonl");
    let new_path = dir.path().join("new.jsonl");

    let old_session = build_old_session();
    let new_session = build_new_session();

    old_session.save_to_path(&old_path).unwrap();
    new_session.save_to_path(&new_path).unwrap();

    // Build the example binary
    let build = Command::new("cargo")
        .args(["build", "--example", "session_diff"])
        .current_dir(env!("CARGO_MANIFEST_DIR"))
        .output()
        .expect("cargo build");
    assert!(
        build.status.success(),
        "build failed:\n{}",
        String::from_utf8_lossy(&build.stderr)
    );

    // Run it
    let output = Command::new("cargo")
        .args([
            "run",
            "--example",
            "session_diff",
            "--",
            old_path.to_str().unwrap(),
            new_path.to_str().unwrap(),
        ])
        .current_dir(env!("CARGO_MANIFEST_DIR"))
        .output()
        .expect("cargo run");

    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);

    assert!(
        output.status.success(),
        "session_diff exited with error:\nstdout: {stdout}\nstderr: {stderr}"
    );

    // Verify sections appear
    assert!(
        stdout.contains("Session Metadata"),
        "missing metadata section:\n{stdout}"
    );
    assert!(
        stdout.contains("Compaction"),
        "missing compaction section:\n{stdout}"
    );
    assert!(
        stdout.contains("Messages"),
        "missing messages section:\n{stdout}"
    );
    assert!(
        stdout.contains("Token Usage"),
        "missing token usage section:\n{stdout}"
    );

    // Compaction was added in new session
    assert!(
        stdout.contains("compaction"),
        "should show new compaction event:\n{stdout}"
    );

    // New message was added
    assert!(
        stdout.contains("New messages"),
        "should report new messages:\n{stdout}"
    );
    assert!(
        stdout.contains("Found one TODO"),
        "should show the new assistant message:\n{stdout}"
    );

    // Token usage changed
    assert!(
        stdout.contains("input_tokens"),
        "should show token usage fields:\n{stdout}"
    );

    // The modified assistant reply should show as a changed message
    assert!(
        stdout.contains("coding, debugging"),
        "should show the changed assistant text:\n{stdout}"
    );
}
"}
